const body = $('채팅 입력').item.json.body;
const output = JSON.parse($('meokurum').item.json.output);

return [{
  userId: body.userId,
  message: body.message,
  bots: output.bots,
  date: output.date,
  is_future: output.is_future,
  location: output.location,
  today: new Date().toISOString().split('T')[0]
}];

const items = $input.all();

const results = {};
items.forEach(item => {
  const json = item.json;
  if (json.meal_type) results.meal = json;
  if (json.content) results.diary = json;
  if (json.title) results.schedule = json;
  if (json.weight !== undefined) results.weight = json;
  if (json.temperature) results.weather = json;
  if (json.sender) results.email = json;
});

return [{ results: JSON.stringify(results) }];
